```php
class PatientController extends ApiController
{
    public function __construct(private PatientService $patientService) {}

    public function index(Request $request): JsonResponse
    {
        $this->authorize('viewAny', Patient::class);
        $query = Patient::with(['socioeconomic', 'user']);
        if ($request->user()->isPatient()) {
            $query->where('user_id', $request->user()->id);
        }
        return $this->paginated('Patients retrieved successfully.', PatientResource::collection($query->paginate()));
    }

    public function store(StorePatientRequest $request): JsonResponse
    {
        $patient = $this->patientService->createPatient(
            $request->safe()->except('socioeconomic'),
            $request->input('socioeconomic')
        );
        return $this->created('Patient created successfully.', ['patient' => new PatientResource($patient)]);
    }

    public function show(Patient $patient): JsonResponse
    {
        $this->authorize('view', $patient);
        return $this->ok('Patient retrieved.', ['patient' => new PatientResource($patient->load(['socioeconomic', 'user']))]);
    }

    public function update(UpdatePatientRequest $request, Patient $patient): JsonResponse
    {
        $patient = $this->patientService->updatePatient(
            $patient,
            $request->safe()->except('socioeconomic'),
            $request->input('socioeconomic')
        );
        return $this->ok('Patient updated successfully.', ['patient' => new PatientResource($patient)]);
    }

    public function destroy(Patient $patient): JsonResponse
    {
        $this->authorize('delete', $patient);
        $patient->delete();
        return $this->noContent();
    }
}
```

Key design notes (Constitution Principles VI + VII):
- Request keys are snake_case — $request->safe()->except('socioeconomic') passes directly to PatientService, no conversion.
- Single-resource responses: $this->created/ok('msg', ['patient' => new PatientResource(...)]) — shape: data.patient.{type,id,attributes,relationships}
- List response: $this->paginated(...) — shape: data:[...], meta, links
- Delete: $this->noContent() — 204 no body
- Never use ->response()->setStatusCode() on Resources.
- JsonResource::with() is not used — no 'included' key in responses.

